const ageGate=document.querySelector('#ageGate');
if(localStorage.getItem('ageConfirmed')==='yes')ageGate.classList.add('hidden');
document.querySelector('#ageYes').onclick=()=>{localStorage.setItem('ageConfirmed','yes');ageGate.classList.add('hidden')};
const checkout=document.querySelector('#checkoutModal'),legal=document.querySelector('#legalModal');
document.querySelectorAll('.buy').forEach(b=>b.onclick=()=>checkout.classList.add('open'));
checkout.querySelectorAll('.x,.x-action').forEach(b=>b.onclick=()=>checkout.classList.remove('open'));
const content={terms:{title:'Termos de uso',text:`<p>Última atualização: 21 de julho de 2026.</p><h4>1. Elegibilidade</h4><p>O serviço é destinado exclusivamente a pessoas com 18 anos ou mais. Ao adquirir o acesso, você declara possuir capacidade legal para contratar.</p><h4>2. Acesso</h4><p>O acesso é pessoal, individual e intransferível. O compartilhamento de convites ou conteúdo pode resultar na remoção do grupo.</p><h4>3. Planos</h4><p>O plano mensal permanece ativo pelo período contratado e depende de renovação. O plano vitalício concede acesso enquanto a comunidade estiver em operação, sujeito ao cumprimento destes termos.</p><h4>4. Conduta</h4><p>É proibido redistribuir conteúdo, assediar membros, praticar fraude ou qualquer atividade ilegal.</p><h4>5. Atendimento</h4><p>Dúvidas e solicitações devem ser encaminhadas ao canal de suporte informado nesta página.</p>`},privacy:{title:'Política de privacidade',text:`<p>Última atualização: 21 de julho de 2026.</p><h4>Dados coletados</h4><p>Podemos tratar nome, e-mail, identificador do Telegram, plano escolhido e informações necessárias para confirmar o pagamento.</p><h4>Finalidade</h4><p>Os dados são usados para processar o acesso, prestar suporte, prevenir fraudes e cumprir obrigações legais.</p><h4>Compartilhamento</h4><p>Dados podem ser processados pelo provedor de pagamentos e pelo Telegram conforme seus próprios termos. Não vendemos dados pessoais.</p><h4>Seus direitos</h4><p>Você pode solicitar acesso, correção ou exclusão de dados, observadas as obrigações legais de retenção, pelo canal de suporte.</p>`}};
document.querySelectorAll('[data-legal]').forEach(b=>b.onclick=()=>{const c=content[b.dataset.legal];document.querySelector('#legalTitle').textContent=c.title;document.querySelector('#legalText').innerHTML=c.text;legal.classList.add('open')});
legal.querySelector('.x').onclick=()=>legal.classList.remove('open');
document.querySelectorAll('.modal').forEach(m=>m.addEventListener('click',e=>{if(e.target===m)m.classList.remove('open')}));
